"      final pos = position!;
      setState(() {
        _currentPosition = pos;
        for (var mosque in _dynamicMosquesList) {
          double dist = _calculateDistance(
            pos.latitude,
            pos.longitude,
            mosque['lat'] as double,
            mosque['lon'] as double,
          );
          mosque['mesafeVal'] = dist;
          mosque['mesafeText'] = "${dist.toStringAsFixed(1)} km";
        }
        _dynamicMosquesList.sort((a, b) => (a['mesafeVal'] as double).compareTo(b['mesafeVal'] as double));
        _loadingLocation = false;
      });"

